#![no_std]
#![no_main]

extern crate alloc;

use uefi::prelude::*;
use linked_list_allocator::LockedHeap;
use alloc::vec::Vec;
use core::ptr;

mod console;
mod commands;
mod pci;
mod drivers;

#[global_allocator]
static ALLOCATOR: LockedHeap = LockedHeap::empty();

#[panic_handler]
fn panic(info: &core::panic::PanicInfo) -> ! {
    let mut vga = drivers::vga::VgaWriter::new();
    vga.set_color(drivers::vga::Color::Red, drivers::vga::Color::Black);
    vga.write_str("\n");
    vga.write_str("╔══════════════════════════════════════╗\n");
    vga.write_str("║         !!! KERNEL PANIC !!!         ║\n");
    vga.write_str("╚══════════════════════════════════════╝\n\n");
    if let Some(loc) = info.location() {
        vga.write_str(&alloc::format!("  {}:{}:{}\n", loc.file(), loc.line(), loc.column()));
    }
    if let Some(msg) = info.message() {
        vga.write_str(&alloc::format!("  {}\n", msg));
    }
    vga.write_str("\nPress RESET button to reboot.\n");
    loop {}
}

#[entry]
fn efi_main(_handle: Handle, mut st: SystemTable<Boot>) -> Status {
    if let Err(_) = uefi_services::init(&mut st) {
        return Status::LOAD_ERROR;
    }

    // ===== 第一阶段：UEFI 输出 =====
    uefi_services::println!();
    uefi_services::println!("╔══════════════════════════════════════╗");
    uefi_services::println!("║        RunST X Kernel v0.3           ║");
    uefi_services::println!("║  FAT32 | TCP/IP | MultiProcess       ║");
    uefi_services::println!("╚══════════════════════════════════════╝");
    uefi_services::println!();
    uefi_services::println!("Build: {}", env!("BUILD_DATE"));
    uefi_services::println!("Git:   {}", env!("GIT_HASH"));
    uefi_services::println!();

    // 初始化堆分配器：4MB
    let heap_size = 4 * 1024 * 1024; // 4MB
    let heap_pages = (heap_size + 0xFFF) / 0x1000;
    let heap_start = match st.boot_services().allocate_pages(
        uefi::table::boot::AllocateType::AnyPages,
        uefi::table::boot::MemoryType::LOADER_DATA,
        heap_pages,
    ) {
        Ok(addr) => addr as *mut u8,
        Err(_) => {
            uefi_services::println!("Failed to allocate heap memory");
            return Status::OUT_OF_RESOURCES;
        }
    };
    unsafe {
        ALLOCATOR.lock().init(heap_start, heap_size);
    }
    uefi_services::println!("Heap: {} MB at 0x{:x}", heap_size / (1024*1024), heap_start as usize);

    // 初始化内存管理器
    unsafe {
        use drivers::memory;
        memory::G_MEMORY_MANAGER = Some(memory::MemoryManager::new());
        memory::G_MEMORY_MANAGER.as_ref().unwrap().init();
    }
    uefi_services::println!("Memory manager initialized (4MB)\n");

    // 初始化进程管理器
    unsafe {
        use drivers::process;
        process::G_PROCESS_MANAGER = Some(process::ProcessManager::new());
    }
    uefi_services::println!("Process manager initialized\n");

    // 枚举 PCI 设备
    let devices = pci::enumerate_pci();
    uefi_services::println!("PCI: {} devices found", devices.len());
    unsafe { PCI_DEVICES = Some(devices); }

    // 查找关键硬件
    if let Some(dev) = pci::find_device(&get_pci_devices(), 0x01, 0x06) {
        uefi_services::println!("  AHCI  at {:02X}:{:02X}.{:02X}", dev.bus, dev.slot, dev.func);
    }
    if let Some(dev) = pci::find_device(&get_pci_devices(), 0x01, 0x04) {
        uefi_services::println!("  SATA  at {:02X}:{:02X}.{:02X}", dev.bus, dev.slot, dev.func);
    }
    if let Some(dev) = pci::find_device(&get_pci_devices(), 0x02, 0x00) {
        uefi_services::println!("  NIC   at {:02X}:{:02X}.{:02X}", dev.bus, dev.slot, dev.func);
    }
    uefi_services::println!();

    // ===== 退出 Boot Services =====
    uefi_services::println!("Exiting Boot Services...");
    let rt = st.exit_boot_services(uefi::table::boot::MemoryMapKey::new());
    let _rt = match rt {
        Ok(r) => r,
        Err(_) => {
            let mut vga = drivers::vga::VgaWriter::new();
            vga.set_color(drivers::vga::Color::Red, drivers::vga::Color::Black);
            vga.write_str("Failed to exit Boot Services\n");
            return Status::ABORTED;
        }
    };

    // ===== 第二阶段：VGA Shell =====
    let mut shell = console::Shell::new();

    shell.write_str("╔══════════════════════════════════════════╗\n");
    shell.write_str("║   RunST X Operating System v0.3          ║\n");
    shell.write_str("║   FAT32 | TCP/IP | MultiProcess          ║\n");
    shell.write_str("║   Type 'help' for available commands      ║\n");
    shell.write_str("╚══════════════════════════════════════════╝\n\n");

    // 初始化硬件驱动
    drivers::keyboard::init();
    shell.write_str("[OK] Keyboard initialized\n");

    let rtc_str = drivers::rtc::Rtc::get_datetime_string();
    shell.write_str(&alloc::format!("[OK] RTC: {}\n", rtc_str));

    // AHCI
    if let Some(dev) = pci::find_device(&get_pci_devices(), 0x01, 0x06) {
        if let Some(ahci) = drivers::ahci::AhciDriver::new(dev) {
            shell.write_str(&alloc::format!("[OK] AHCI: {} ports\n", ahci.port_count()));
            for p in 0..ahci.port_count() {
                if ahci.is_connected(p) {
                    let sig = ahci.get_signature(p);
                    shell.write_str(&alloc::format!("    Port {}: Connected (SIG=0x{:08X})\n", p, sig));
                }
            }
        }
    } else {
        shell.write_str("[!!] AHCI: not found (no disk)\n");
    }

    // RTL8139
    if let Some(dev) = pci::find_device(&get_pci_devices(), 0x02, 0x00) {
        if let Some(mut rtl) = drivers::rtl8139::Rtl8139::new(dev) {
            let mac = rtl.mac_addr();
            shell.write_str(&alloc::format!("[OK] RTL8139: MAC {:02X}:{:02X}:{:02X}:{:02X}:{:02X}:{:02X}\n",
                mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]));
            rtl.init();
            shell.write_str("[OK] Network: initialized\n");
        }
    } else {
        shell.write_str("[!!] RTL8139: not found\n");
    }

    shell.write_str("\n");

    // 注册示例进程
    {
        use drivers::process::ProcessState;

        fn idle_task() -> ProcessState {
            ProcessState::Running
        }

        let pm = drivers::process::get_process_manager();
        pm.spawn("idle", idle_task);
        shell.write_str("[OK] Process 'idle' started (PID 0)\n");
    }

    shell.write_str("\n");

    // 主循环：命令 Shell
    loop {
        shell.print_prompt();
        if let Some(line) = shell.read_line() {
            commands::dispatch(&mut shell, line);
        }
    }
}

// 全局 PCI 设备列表
static mut PCI_DEVICES: Option<Vec<pci::PciDevice>> = None;

pub fn get_pci_devices() -> &'static [pci::PciDevice] {
    unsafe { PCI_DEVICES.as_ref().map(|v| v.as_slice()).unwrap_or(&[]) }
}

