use crate::console::Shell;
use crate::drivers::memory;

pub fn run(shell: &mut Shell) {
    let info = memory::MemInfo::get();
    shell.write_str(&alloc::format!("Memory Manager:\n"));
    shell.write_str(&alloc::format!("  Total:  {} KB\n", info.total / 1024));
    shell.write_str(&alloc::format!("  Used:   {} KB\n", info.used / 1024));
    shell.write_str(&alloc::format!("  Free:   {} KB\n", info.free / 1024));
