use crate::console::Shell;
use crate::get_pci_devices;
use crate::drivers::rtl8139::Rtl8139;
use crate::drivers::tcpip;

const PING_TIMEOUT_MS: u64 = 1000;
const PING_MAX_RETRIES: u32 = 4;

pub fn run(shell: &mut Shell, args: &[&str]) {
    if args.is_empty() {
        shell.write_str("Usage: ping <IP>\nExample: ping 192.168.1.1\n");
        return;
    }

    let ip_str = args[0];
    let parts: Vec<u8> = ip_str.split('.')
        .filter_map(|s| s.parse().ok())
        .collect();

    if parts.len() != 4 {
        shell.write_str("Invalid IP address.\n");
        return;
    }

    let target_ip = tcpip::IpHeader::to_ip(parts[0], parts[1], parts[2], parts[3]);
    let target_str = tcpip::IpHeader::ip_to_str(target_ip);

    shell.write_str(&alloc::format!("Pinging {} ...\n", ip_str));

    let mut success_count = 0;
    let mut total_rtt = 0u64;

    for seq in 0..PING_MAX_RETRIES {
        let rtt = do_ping(target_ip, PING_TIMEOUT_MS, seq as u16);

        if rtt > 0 {
            shell.write_str(&alloc::format!("  Reply from {}: time={}ms\n", ip_str, rtt));
            success_count += 1;
            total_rtt += rtt;
        } else {
            shell.write_str(&alloc::format!("  Request timed out ({}ms)\n", PING_TIMEOUT_MS));
        }
    }

    if success_count > 0 {
        let avg = total_rtt / success_count as u64;
        let loss = ((PING_MAX_RETRIES - success_count) * 100) / PING_MAX_RETRIES;
        shell.write_str(&alloc::format!(
            "{} packets transmitted, {} received, {}% loss, avg rtt {}ms\n",
            PING_MAX_RETRIES, success_count, loss, avg
        ));
    } else {
        shell.write_str(&alloc::format!("All {} packets lost.\n", PING_MAX_RETRIES));
    }
}

fn do_ping(target_ip: u32, timeout_ms: u64, seq: u16) -> u64 {
    let start = get_time_ms();
    let devices = get_pci_devices();

    if let Some(dev) = crate::pci::find_device(devices, 0x02, 0x00) {
        if let Some(mut rtl) = Rtl8139::new(dev) {
            let mac = rtl.mac_addr();
            rtl.init();

            // 构造 ICMP Echo Request
            let mut icmp = tcpip::IcmpHeader::new(seq, seq);
            icmp.calc_checksum();

            // 构造 IP 头部
            let mut ip_hdr = tcpip::IpHeader {
                version_ihl: 0x45,
                dscp_ecn: 0,
                total_length: (core::mem::size_of::<tcpip::IpHeader>() + core::mem::size_of::<tcpip::IcmpHeader>()) as u16,
                identification: 0,
                flags_fragment: 0,
                ttl: 64,
                protocol: tcpip::IPPROTO_ICMP,
                checksum: 0,
                src_ip: 0,
                dst_ip: target_ip,
            };
            ip_hdr.checksum = tcpip::checksum(
                unsafe { core::slice::from_raw_parts(&ip_hdr as *const _ as *const u8, core::mem::size_of::<tcpip::IpHeader>()) }
            );

            // 发送
            let mut frame = alloc::vec::Vec::new();
            frame.extend_from_slice(&[0xFFu8; 6]);
            frame.extend_from_slice(&mac);
            frame.extend_from_slice(&[0x08, 0x00]);
            unsafe {
                frame.extend_from_slice(core::slice::from_raw_parts(&ip_hdr as *const _ as *const u8, core::mem::size_of::<tcpip::IpHeader>()));
            }
            unsafe {
                frame.extend_from_slice(core::slice::from_raw_parts(&icmp as *const _ as *const u8, core::mem::size_of::<tcpip::IcmpHeader>()));
            }

            rtl.send(&frame);

            // 带超时的轮询等待回复
            let mut retries = timeout_ms * 10;
            while retries > 0 {
                let mut recv_buf = [0u8; 1500];
                if let Some(len) = rtl.recv(&mut recv_buf) {
                    if len >= 42 {  // IP(20) + ICMP(8) minimum
                        let icmp_type = recv_buf[20];
                        if icmp_type == 0 {  // ICMP Echo Reply
                            let elapsed = get_time_ms() - start;
                            return elapsed;
                        }
                    }
                }
                core::hint::spin_loop();
                retries -= 1;
            }
        }
    }
    0
}

fn get_time_ms() -> u64 {
    unsafe { core::arch::x86_64::_rdtsc() / 1_000_000 }
}

