use core::ptr;
use core::mem;
use core::slice;
use alloc::alloc::{alloc, dealloc, Layout};
use crate::pci::PciDevice;

// ========== AHCI 常量 ==========
const AHCI_CLASS: u8 = 0x01;
const AHCI_SUBCLASS: u8 = 0x06;
const AHCI_PROG_IF: u8 = 0x01;
const AHCI_CMD_READ_DMA_EXT: u8 = 0x25;
const AHCI_CMD_WRITE_DMA_EXT: u8 = 0x35;
const CMD_SLOT_COUNT: usize = 32;
const MAX_SECTORS_PER_DMA: u8 = 255;

// ========== HBA 结构体 ==========
#[repr(C)]
pub struct AhciHb {
    pub cap: u32,
    pub ghc: u32,
    pub is: u32,
    pub pi: u32,
    pub vs: u32,
    pub ccc_ctl: u32,
    pub ccc_ports: u32,
    pub em_loc: u32,
    pub em_ctl: u32,
    pub cap2: u32,
    pub bohc: u32,
    pub reserved: [u8; 0xA0],
    pub ports: [AhciPort; 32],
}

#[repr(C, packed)]
pub struct AhciPort {
    pub clb: u32,
    pub clbu: u32,
    pub fb: u32,
    pub fbu: u32,
    pub is: u32,
    pub ie: u32,
    pub cmd: u32,
    pub reserved0: u32,
    pub tfd: u32,
    pub sig: u32,
    pub ssts: u32,
    pub sctl: u32,
    pub serr: u32,
    pub sact: u32,
    pub ci: u32,
    pub sntf: u32,
    pub fbs: u32,
    pub reserved1: [u32; 11],
    pub vendor: [u32; 4],
}

#[repr(C, packed)]
pub struct AhciCmdHeader {
    pub cfl: u16,
    pub a: u16,
    pub prdtl: u16,
    pub prd_count: u32,
    pub ctba: u32,
    pub ctbau: u32,
    pub reserved: [u32; 4],
}

#[repr(C, packed)]
pub struct AhciPrdt {
    pub dba: u32,
    pub dbau: u32,
    pub reserved: u32,
    pub byte_count: u32,
}

#[repr(C, packed)]
pub struct AhciCmdTable {
    pub cfis: [u8; 64],
    pub acmd: [u8; 32],
    pub reserved: [u8; 32],
    pub prdt: [AhciPrdt; 1],
}

// ========== DMA 内存分配器（Redox OS 风格） ==========
pub struct DmaMemory {
    pub virt: *mut u8,
    pub phys: u32,
    pub size: usize,
}

impl DmaMemory {
    pub fn new(size: usize) -> Option<Self> {
        let layout = Layout::from_size_align(size, 128).ok()?;
        let virt = unsafe { alloc(layout) };
        if virt.is_null() {
            return None;
        }
        unsafe {
            ptr::write_bytes(virt, 0, size);
        }
        Some(Self {
            virt,
            phys: virt as u32,
            size,
        })
    }
}

impl Drop for DmaMemory {
    fn drop(&mut self) {
        unsafe {
            dealloc(self.virt, Layout::from_size_align(self.size, 128).unwrap());
        }
    }
}

// ========== AHCI 磁盘驱动（Redox OS 风格） ==========
pub struct AhciDisk {
    port: u8,
    port_ptr: *mut AhciPort,
    clb: DmaMemory,
    ctbas: [DmaMemory; CMD_SLOT_COUNT],
    fb: DmaMemory,
    buf: DmaMemory,
    size: u64,
}

impl AhciDisk {
    pub fn new(port: u8, port_ptr: *mut AhciPort) -> Option<Self> {
        // 分配命令列表
        let clb = DmaMemory::new(1024)?;
        // 分配命令表（32个命令槽）
        let mut ctbas: [DmaMemory; CMD_SLOT_COUNT] = unsafe { mem::zeroed() };
        for i in 0..CMD_SLOT_COUNT {
            ctbas[i] = DmaMemory::new(mem::size_of::<AhciCmdTable>())?;
        }
        let fb = DmaMemory::new(256)?;  // FIS 接收区
        let buf = DmaMemory::new(256 * 512)?;  // 数据缓冲区

        unsafe {
            // 设置命令列表基址
            ptr::write_volatile(&mut (*port_ptr).clb, clb.phys);
            ptr::write_volatile(&mut (*port_ptr).clbu, 0);
            // 设置 FIS 基址
            ptr::write_volatile(&mut (*port_ptr).fb, fb.phys);
            ptr::write_volatile(&mut (*port_ptr).fbu, 0);
        }

        // 识别设备获取大小
        let size = unsafe { identify_device(port_ptr, &clb, &ctbas) };

        Some(Self {
            port, port_ptr, clb, ctbas, fb, buf, size,
        })
    }

    pub fn size(&self) -> u64 {
        self.size
    }

    // ========== DMA 读 ==========
    pub fn read(&mut self, block: u64, buffer: &mut [u8]) -> Result<usize, &'static str> {
        let sectors = buffer.len() / 512;
        if sectors == 0 {
            return Ok(0);
        }

        let mut sector = 0;
        while sector < sectors {
            let count = (sectors - sector).min(MAX_SECTORS_PER_DMA as usize) as u8;
            let lba = block + sector as u64;

            if !self.ata_dma(lba, count, false) {
                return Err("DMA read failed");
            }

            unsafe {
                ptr::copy(
                    self.buf.virt,
                    buffer.as_mut_ptr().add(sector * 512),
                    count as usize * 512,
                );
            }
            sector += count as usize;
        }
        Ok(sector * 512)
    }

    // ========== DMA 写 ==========
    pub fn write(&mut self, block: u64, buffer: &[u8]) -> Result<usize, &'static str> {
        let sectors = buffer.len() / 512;
        if sectors == 0 {
            return Ok(0);
        }

        let mut sector = 0;
        while sector < sectors {
            let count = (sectors - sector).min(MAX_SECTORS_PER_DMA as usize) as u8;
            let lba = block + sector as u64;

            unsafe {
                ptr::copy(
                    buffer.as_ptr().add(sector * 512),
                    self.buf.virt,
                    count as usize * 512,
                );
            }

            if !self.ata_dma(lba, count, true) {
                return Err("DMA write failed");
            }
            sector += count as usize;
        }
        Ok(sector * 512)
    }

    // ========== ATA DMA 命令执行 ==========
    fn ata_dma(&mut self, lba: u64, count: u8, write: bool) -> bool {
        unsafe {
            let port_ptr = &mut *self.port_ptr;

            // 1. 检查端口状态
            let ssts = ptr::read_volatile(&port_ptr.ssts);
            if (ssts & 0x0F) != 0x03 {
                return false;
            }

            // 2. 等待端口就绪
            let mut timeout = 1000000;
            while (ptr::read_volatile(&port_ptr.tfd) & 0x88) != 0 && timeout > 0 {
                timeout -= 1;
            }
            if timeout == 0 {
                return false;
            }

            // 3. 获取命令槽（使用 slot 0）
            let slot = 0;

            // 4. 填充命令头
            let cmd_header = &mut *(self.clb.virt.add(slot * 32) as *mut AhciCmdHeader);
            cmd_header.cfl = 5;  // FIS 长度 5 DW
            cmd_header.a = 0;
            cmd_header.prdtl = 1;
            cmd_header.ctba = self.ctbas[slot].phys;
            cmd_header.ctbau = 0;

            // 5. 填充命令表
            let cmd_table = &mut *(self.ctbas[slot].virt as *mut AhciCmdTable);
            let cfis = &mut cmd_table.cfis;

            // FIS: 寄存器主机到设备（0x27）
            cfis[0] = 0x27;
            cfis[1] = 0x80;  // 命令
            cfis[2] = if write { AHCI_CMD_WRITE_DMA_EXT } else { AHCI_CMD_READ_DMA_EXT };
            cfis[3] = 0x00;
            // LBA (48位)
            cfis[4] = (lba & 0xFF) as u8;
            cfis[5] = ((lba >> 8) & 0xFF) as u8;
            cfis[6] = ((lba >> 16) & 0xFF) as u8;
            cfis[7] = ((lba >> 24) & 0xFF) as u8;
            cfis[8] = ((lba >> 32) & 0xFF) as u8;
            cfis[9] = ((lba >> 40) & 0xFF) as u8;
            cfis[10] = count;
            cfis[11] = 0x00;
            cfis[12] = 0x00;
            cfis[13] = 0x00;

            // 6. PRDT（物理区域描述符表）
            let prdt = &mut cmd_table.prdt[0];
            prdt.dba = self.buf.phys;
            prdt.dbau = 0;
            prdt.byte_count = ((count as usize * 512) - 1) | 0x80000000;

            // 7. 清空命令完成位和中断状态
            ptr::write_volatile(&mut port_ptr.ci, 0);
            ptr::write_volatile(&mut port_ptr.is, 0xFFFFFFFF);

            core::sync::atomic::compiler_fence(core::sync::atomic::Ordering::SeqCst);

            // 8. 发起命令
            ptr::write_volatile(&mut port_ptr.ci, 1 << slot);

            // 9. 等待完成
            let mut timeout2 = 1000000;
            while (ptr::read_volatile(&mut port_ptr.ci) & (1 << slot)) != 0 && timeout2 > 0 {
                timeout2 -= 1;
            }
            if timeout2 == 0 {
                return false;
            }

            // 10. 检查错误
            let is = ptr::read_volatile(&mut port_ptr.is);
            if is & 0x40000000 != 0 {
                return false;
            }

            true
        }
    }
}

// ========== 设备识别 ==========
unsafe fn identify_device(port: *mut AhciPort, clb: &DmaMemory, ctbas: &[DmaMemory; CMD_SLOT_COUNT]) -> u64 {
    let mut size = 0u64;
    // 标准 ATA Identify 流程
    // 简化实现：返回 0 表示识别失败
    // 完整实现需要发送 Identify 命令并解析响应
    size
}

// ========== AHCI 管理器 ==========
pub struct AhciManager {
    pub disks: alloc::vec::Vec<AhciDisk>,
}

impl AhciManager {
    pub fn new(device: &PciDevice) -> Option<Self> {
        if device.header.class != AHCI_CLASS
            || device.header.subclass != AHCI_SUBCLASS
            || device.header.prog_if != AHCI_PROG_IF {
            return None;
        }

        let abar = device.header.bar5 & 0xFFFFFFF0;
        if abar == 0 {
            return None;
        }

        // 开启总线主控
        crate::pci::write_config_u32(
            device.bus, device.slot, device.func, 0x04,
            (device.header.command as u32) | 0x04 | 0x02,
        );

        let hb = abar as *mut AhciHb;
        unsafe {
            // 启用 AHCI
            let ghc = ptr::read_volatile(&(*hb).ghc);
            ptr::write_volatile(&mut (*hb).ghc, ghc | 0x80000000);

            let cap = ptr::read_volatile(&(*hb).cap);
            let port_count = ((cap >> 20) & 0x1F) as u8;

            let mut disks = alloc::vec::Vec::new();
            let pi = ptr::read_volatile(&(*hb).pi);
            for port in 0..port_count {
                if pi & (1 << port) != 0 {
                    let port_ptr = &mut (*hb).ports[port as usize];
                    // 启动端口
                    let cmd = ptr::read_volatile(&port_ptr.cmd);
                    ptr::write_volatile(&mut port_ptr.cmd, cmd | 0x0010 | 0x0002);

                    // 尝试创建磁盘
                    if let Some(disk) = AhciDisk::new(port, port_ptr) {
                        disks.push(disk);
                    }
                }
            }

            if disks.is_empty() {
                None
            } else {
                Some(Self { disks })
            }
        }
    }
}

