use alloc::vec::Vec;
use alloc::string::String;

// 块设备接口
pub trait BlockDevice: Send + Sync {
    fn read_sector(&mut self, sector: u32, buf: &mut [u8; 512]) -> bool;
    fn write_sector(&mut self, sector: u32, buf: &[u8; 512]) -> bool;
