}

#[repr(C, packed)]
#[derive(Clone, Copy)]
pub struct DirEntry {
    pub name: [u8; 11],
    pub attr: u8,
    pub nt_reserved: u8,
    pub create_time_tenth: u8,
    pub create_time: u16,
    pub create_date: u16,
    pub access_date: u16,
    pub cluster_high: u16,
    pub modify_time: u16,
    pub modify_date: u16,
    pub cluster_low: u16,
    pub size: u32,
}

impl DirEntry {
    pub fn is_empty(&self) -> bool {
        self.name[0] == 0x00 || self.name[0] == 0xE5
    }

    pub fn is_directory(&self) -> bool {
        (self.attr & 0x10) != 0
    }

    pub fn name_str(&self) -> String {
        let mut name = String::new();
        for i in 0..11 {
            if self.name[i] == 0x00 { break; }
            if self.name[i] == 0x20 { continue; }
            name.push(self.name[i] as char);
        }
        if self.name[8] != 0x20 && self.name[8] != 0x00 {
            name.push('.');
            for i in 8..11 {
                if self.name[i] == 0x20 { break; }
                name.push(self.name[i] as char);
            }
        }
        name.to_lowercase()
    }

    pub fn cluster(&self) -> u32 {
        ((self.cluster_high as u32) << 16) | (self.cluster_low as u32)
    }
}

impl Fat32Fs {
    pub fn new(disk: Box<dyn BlockDevice>) -> Option<Self> {
        let mut bpb_buf = [0u8; 512];
        if !disk.read_sector(1, &mut bpb_buf) {
            return None;
        }

        let bpb = unsafe { &*(bpb_buf.as_ptr() as *const Bpb) };

        if bpb.filesystem_type != *b"FAT32   " && bpb.filesystem_type != *b"FAT32 " {
            return None;
        }

        let data_start_sector = bpb.reserved_sectors as u32
            + (bpb.fat_count as u32) * bpb.sectors_per_fat as u32;
        let cluster_size_sectors = bpb.sectors_per_cluster as u32;

        Some(Self {
            bpb: *bpb,
            data_start_sector,
            cluster_size_sectors,
            fat_start_sector: bpb.reserved_sectors as u32,
            sectors_per_fat: bpb.sectors_per_fat as u32,
            root_cluster: bpb.root_cluster,
            disk: Some(disk),
        })
    }

    fn cluster_to_sector(&self, cluster: u32) -> u32 {
        self.data_start_sector + (cluster - 2) * self.cluster_size_sectors
    }

    fn read_fat_entry(&self, cluster: u32) -> u32 {
        let mut disk = match self.disk.clone() {
            Some(d) => d,
            None => return 0,
        };
        let fat_offset = cluster * 4;
        let sector = self.fat_start_sector + fat_offset / 512;
        let offset = fat_offset % 512;

        let mut buf = [0u8; 512];
        if !disk.read_sector(sector, &mut buf) {
            return 0;
        }

        let val = u32::from_le_bytes([
            buf[offset], buf[offset + 1], buf[offset + 2], buf[offset + 3],
        ]);
        val & 0x0FFFFFFF
    }

    fn read_cluster_chain(&self, start_cluster: u32) -> Vec<u32> {
        let mut clusters = Vec::new();
        let mut current = start_cluster;
        while current > 0 && current < 0x0FFFFFF8 {
            clusters.push(current);
            current = self.read_fat_entry(current);
        }
        clusters
    }

    pub fn read_file(&mut self, cluster: u32, size: u32, buf: &mut [u8]) -> bool {
        let mut disk = match self.disk.take() {
            Some(d) => d,
            None => return false,
        };
        let clusters = self.read_cluster_chain(cluster);

        let mut bytes_read = 0u32;
        for cl in &clusters {
            if bytes_read >= size { break; }

            let sector = self.cluster_to_sector(*cl);
            let bytes_in_cluster = (self.cluster_size_sectors * 512) as u32;
            let to_read = core::cmp::min(bytes_in_cluster, size - bytes_read);

            let sectors_needed = ((to_read + 511) / 512) as usize;
            let mut sector_buf = [0u8; 512];
            for s in 0..sectors_needed {
                if !disk.read_sector(sector + s as u32, &mut sector_buf) {
                    self.disk = Some(disk);
                    return false;
                }
                let start = (s * 512) as usize;
                let end = core::cmp::min(start + 512, to_read as usize);
                let copy_start = (bytes_read / 512 * 512) as usize;
                let copy_end = core::cmp::min(copy_start + (end - start), buf.len());
                if copy_end > copy_start {
                    let src_start = start;
                    let src_end = start + core::cmp::min(end - start, 512);
                    let dst_start = copy_start;
                    let dst_end = copy_end;
                    let copy_len = core::cmp::min(src_end - src_start, dst_end - dst_start);
                    if copy_len > 0 {
                        core::ptr::copy_nonoverlapping(
                            sector_buf.as_ptr().add(src_start),
                            buf.as_mut_ptr().add(dst_start),
                            copy_len,
                        );
                    }
                }
                bytes_read += (end - start) as u32;
            }
        }

        self.disk = Some(disk);
        bytes_read == size
    }

    pub fn read_directory<F: FnMut(&DirEntry)>(&mut self, cluster: u32, mut callback: F) {
        let mut disk = match self.disk.take() {
            Some(d) => d,
            None => return,
        };

        let clusters = self.read_cluster_chain(cluster);

        for cl in &clusters {
            let sector = self.cluster_to_sector(*cl);
            let entries_per_sector = 512 / 32;

            let mut sector_buf = [0u8; 512];
            for s in 0..self.cluster_size_sectors {
                if !disk.read_sector(sector + s, &mut sector_buf) { break; }

                for entry_idx in 0..entries_per_sector {
                    let offset = entry_idx * 32;
                    if offset + 32 > 512 { break; }
                    let entry = unsafe {
                        &*(sector_buf[offset..offset + 32].as_ptr() as *const DirEntry)
                    };

                    if entry.is_empty() { break; }
                    if entry.name[0] == 0x0E { continue; }

                    callback(entry);
                }
            }
        }

        self.disk = Some(disk);
    }
}

