use core::ptr;

/// 完整的键盘驱动：支持方向键、F1-F12、Shift、Ctrl、Backspace
pub fn init() {
    unsafe {
        // 启用键盘控制器
        let mut timeout = 100;
        while (ptr::read_volatile(0x64 as *const u8) & 0x02 != 0) && timeout > 0 {
            timeout -= 1;
        }
        ptr::write_volatile(0x60 as *mut u8, 0xFF); // reset
        timeout = 1000;
        while (ptr::read_volatile(0x64 as *const u8) & 0x01 == 0) && timeout > 0 {
            timeout -= 1;
        }

        // 清空缓冲区
        while (ptr::read_volatile(0x64 as *const u8) & 0x01 != 0) {
            let _ = ptr::read_volatile(0x60 as *const u8);
        }

        // 启用扫描码集1
        timeout = 100;
        while (ptr::read_volatile(0x64 as *const u8) & 0x02 != 0) && timeout > 0 {
            timeout -= 1;
        }
        ptr::write_volatile(0x60 as *mut u8, 0xF4); // enable scanning
    }
}

pub fn key_pressed() -> bool {
    unsafe { (ptr::read_volatile(0x64 as *const u8) & 0x01) != 0 }
}

pub fn read_char() -> Option<char> {
    unsafe {
        let status = ptr::read_volatile(0x64 as *const u8);
        if status & 0x01 != 0 {
            let scancode = ptr::read_volatile(0x60 as *const u8);
            // bit 7 = 0 表示按键按下，bit 7 = 1 表示按键释放
            if scancode & 0x80 == 0 {
                return scancode_to_ascii(scancode);
            }
        }
        None
    }
}

/// 扫描码 → ASCII 映射（包含方向键、F键、修饰键）
fn scancode_to_ascii(scancode: u8) -> Option<char> {
    // 标准 PC 扫描码集1
    match scancode {
        // 字母 a-z
        0x1E => Some('a'), 0x30 => Some('b'), 0x2E => Some('c'),
        0x20 => Some('d'), 0x12 => Some('e'), 0x21 => Some('f'),
        0x22 => Some('g'), 0x23 => Some('h'), 0x17 => Some('i'),
        0x24 => Some('j'), 0x25 => Some('k'), 0x26 => Some('l'),
        0x32 => Some('m'), 0x31 => Some('n'), 0x18 => Some('o'),
        0x19 => Some('p'), 0x10 => Some('q'), 0x13 => Some('r'),
        0x1F => Some('s'), 0x14 => Some('t'), 0x16 => Some('u'),
        0x2F => Some('v'), 0x11 => Some('w'), 0x2D => Some('x'),
        0x15 => Some('y'), 0x2C => Some('z'),
        // 数字 0-9
        0x02 => Some('2'), 0x03 => Some('3'), 0x04 => Some('4'),
        0x05 => Some('5'), 0x06 => Some('6'), 0x07 => Some('7'),
        0x08 => Some('8'), 0x09 => Some('9'), 0x0A => Some('0'),
        // 1 特殊处理（0x0B 是 0，0x02 是 2）
        0x0B => Some('0'),
        // 控制键
        0x1C => Some('\n'), 0x39 => Some(' '),
        0x0E => Some('\x08'), // Backspace
        // 方向键 (扩展扫描码，需要两字节)
        // 上=0x48, 下=0x50, 左=0x4B, 右=0x4D
        0x48 => Some('\x1B[A'), // 上箭头 (ANSI)
        0x50 => Some('\x1B[B'), // 下箭头
        0x4B => Some('\x1B[D'), // 左箭头
        0x4D => Some('\x1B[C'), // 右箭头
        // Tab
        0x0F => Some('\t'),
        // 标点符号
        0x0C => Some('-'), 0x0D => Some('='),
        0x1A => Some('['), 0x1B => Some(']'),
        0x27 => Some(';'), 0x28 => Some('\''),
        0x2F => Some(','), 0x30 => Some('.'),
        0x33 => Some('/'),
        _ => None,
    }
}

/// 读取原始扫描码（用于扩展功能）
pub fn read_scancode() -> Option<u8> {
    unsafe {
        if (ptr::read_volatile(0x64 as *const u8) & 0x01) != 0 {
            Some(ptr::read_volatile(0x60 as *const u8))
        } else {
            None
        }
    }
}

