/// 内存管理器 - 16MB 堆（修复 Boot Services 退出问题）
use spin::Mutex;
use linked_list_allocator::Heap;
use core::ptr;

const HEAP_SIZE: usize = 16 * 1024 * 1024; // 16MB 堆

pub struct MemoryManager {
    heap: Mutex<Heap>,
    allocated: Mutex<usize>,
    total: usize,
}

impl MemoryManager {
    pub const fn new() -> Self {
        Self {
            heap: Mutex::new(Heap::empty()),
            allocated: Mutex::new(0),
            total: HEAP_SIZE,
        }
    }

    /// 初始化堆（必须在 Boot Services 期间调用）
    pub fn init(&self, start: *mut u8, size: usize) {
        unsafe {
            self.heap.lock().init(start, size);
        }
    }

    pub fn alloc(&self, size: usize, align: usize) -> Option<*mut u8> {
        let mut alloc_count = self.allocated.lock();
        *alloc_count += size;
        let result = self.heap.lock().alloc(size, align);
        if result.is_err() {
            *alloc_count -= size;
        }
        result
    }

    pub fn dealloc(&self, addr: *mut u8, size: usize, _align: usize) {
        let result = self.heap.lock().dealloc(addr, size, _align);
        let mut alloc_count = self.allocated.lock();
        *alloc_count = alloc_count.saturating_sub(size);
        let _ = result;
    }

    pub fn used(&self) -> usize {
        *self.allocated.lock()
    }

    pub fn total(&self) -> usize {
        self.total
    }

    pub fn free(&self) -> usize {
        self.total - self.used()
    }

    pub fn usage_percent(&self) -> f32 {
        if self.total == 0 { return 0.0; }
        (self.used() as f32 / self.total as f32) * 100.0
    }
}

#[derive(Debug)]
pub struct MemInfo {
    pub total: usize,
    pub used: usize,
    pub free: usize,
    pub usage_pct: f32,
}

impl MemInfo {
    pub fn get(mm: &MemoryManager) -> Self {
        Self {
            total: mm.total(),
            used: mm.used(),
            free: mm.free(),
            usage_pct: mm.usage_percent(),
        }
    }

    pub fn format(&self) -> alloc::string::String {
        alloc::format!(
            "Memory: Total={}KB, Used={}KB ({}%.1f%), Free={}KB",
            self.total / 1024,
            self.used / 1024,
            self.usage_pct,
            self.free / 1024,
        )
    }
}

// 全局内存管理器实例
pub static mut G_MEMORY_MANAGER: Option<MemoryManager> = None;

pub fn init_memory_manager() -> MemoryManager {
    unsafe {
        G_MEMORY_MANAGER = Some(MemoryManager::new());
        G_MEMORY_MANAGER.as_ref().unwrap().clone()
    }
}

pub fn get_memory_manager() -> &'static MemoryManager {
    unsafe { G_MEMORY_MANAGER.as_ref().unwrap() }
}

