/// 抢占式进程调度器（maestro 风格）
use alloc::collections::BTreeMap;
use core::sync::atomic::{AtomicU64, Ordering};

// ========== 进程状态 ==========
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum ProcessState {
    Ready,
    Running,
    Blocked,
    Terminated,
}

// ========== 进程结构 ==========
pub struct Process {
    pub id: u64,
    pub name: alloc::string::String,
    pub state: ProcessState,
    pub time_slice: u64,
    pub priority: u8,
}

impl Process {
    pub fn new(id: u64, name: &str, priority: u8) -> Self {
        Self {
            id,
            name: name.into(),
            state: ProcessState::Ready,
            time_slice: 10,
            priority,
        }
    }
}

// ========== 调度器（maestro 风格） ==========
pub struct Scheduler {
    processes: BTreeMap<u64, Process>,
    current: Option<u64>,
    next_pid: u64,
    total_ticks: AtomicU64,
    running_count: usize,
}

impl Scheduler {
    pub const fn new() -> Self {
        Self {
            processes: BTreeMap::new(),
            current: None,
            next_pid: 1,
            total_ticks: AtomicU64::new(0),
            running_count: 0,
        }
    }

    pub fn spawn(&mut self, name: &str, priority: u8) -> u64 {
        let pid = self.next_pid;
        self.next_pid += 1;

        let process = Process::new(pid, name, priority);
        self.processes.insert(pid, process);
        self.running_count += 1;
        pid
    }

    pub fn kill(&mut self, pid: u64) -> bool {
        if let Some(proc) = self.processes.get_mut(&pid) {
            proc.state = ProcessState::Terminated;
            self.running_count = self.running_count.saturating_sub(1);
            true
        } else {
            false
        }
    }

    // ========== 时钟中断处理（抢占式调度核心） ==========
    pub fn tick(&mut self) {
        self.total_ticks.fetch_add(1, Ordering::Relaxed);

        if self.running_count == 0 {
            return;
        }

        let current_pid = match self.current {
            Some(pid) => pid,
            None => {
                // 首次调度：选择第一个就绪进程
                self.switch_to_next();
                return;
            }
        };

        // 递减当前进程的时间片
        if let Some(proc) = self.processes.get_mut(&current_pid) {
            if proc.time_slice > 0 {
                proc.time_slice -= 1;
            }

            // 时间片用完或进程被阻塞，切换
            if proc.time_slice == 0 || proc.state != ProcessState::Running {
                proc.state = ProcessState::Ready;
                self.switch_to_next();
            }
        }
    }

    // ========== 切换到下一个进程 ==========
    fn switch_to_next(&mut self) {
        let current_pid = self.current;

        // 查找下一个就绪进程
        let next_pid = self.find_next_ready();

        if let Some(pid) = next_pid {
            // 重置时间片
            if let Some(proc) = self.processes.get_mut(&pid) {
                proc.time_slice = 10;
                proc.state = ProcessState::Running;
            }

            self.current = Some(pid);
        }
    }

    fn find_next_ready(&self) -> Option<u64> {
        let start = self.current.unwrap_or(0);
        // 从下一个 PID 开始找
        for (pid, proc) in self.processes.iter() {
            if *pid > start && proc.state == ProcessState::Ready {
                return Some(*pid);
            }
        }
        // 从头开始找
        for (pid, proc) in self.processes.iter() {
            if *pid != start && proc.state == ProcessState::Ready {
                return Some(*pid);
            }
        }
        None
    }

    pub fn list_processes(&self) -> Vec<(u64, &str, ProcessState)> {
        let mut result = Vec::new();
        for (id, proc) in &self.processes {
            if proc.state != ProcessState::Terminated {
                result.push((*id, proc.name.as_str(), proc.state));
            }
        }
        result
    }

    pub fn current(&self) -> Option<u64> {
        self.current
    }

    pub fn current_name(&self) -> Option<&str> {
        self.current.and_then(|pid| {
            self.processes.get(&pid).map(|p| p.name.as_str())
        })
    }

    pub fn running_count(&self) -> usize {
        self.running_count
    }
}

// 全局调度器
pub static mut G_SCHEDULER: Option<Scheduler> = None;

pub fn init_scheduler() {
    unsafe {
        G_SCHEDULER = Some(Scheduler::new());
    }
}

pub fn get_scheduler() -> &'static Scheduler {
    unsafe { G_SCHEDULER.as_ref().unwrap() }
}

