/// TCP/IP 网络栈 - Redox OS + rust_os 风格
use crate::drivers::rtl8139::Rtl8139;

// ========== IP 协议常量 ==========
pub const IPPROTO_ICMP: u8 = 1;
pub const IPPROTO_UDP: u8 = 17;
pub const IPPROTO_TCP: u8 = 6;

// ========== IP 头部 ==========
#[repr(C)]
pub struct IpHeader {
    pub version_ihl: u8,
    pub dscp_ecn: u8,
    pub total_length: u16,
    pub identification: u16,
    pub flags_fragment: u16,
    pub ttl: u8,
    pub protocol: u8,
    pub checksum: u16,
    pub src_ip: u32,
    pub dst_ip: u32,
}

impl IpHeader {
    pub fn to_ip(a: u8, b: u8, c: u8, d: u8) -> u32 {
        (a as u32) | ((b as u32) << 8) | ((c as u32) << 16) | ((d as u32) << 24)
    }

    pub fn ip_to_str(ip: u32) -> alloc::string::String {
        alloc::format!(
            "{}.{}.{}.{}",
            ip as u8,
            (ip >> 8) as u8,
            (ip >> 16) as u8,
            (ip >> 24) as u8,
        )
    }

    pub fn calc_checksum(&mut self) {
        unsafe {
            self.checksum = 0;
            let slice = core::slice::from_raw_parts(
                self as *mut _ as *const u8,
                core::mem::size_of::<IpHeader>(),
            );
            self.checksum = checksum(slice);
        }
    }
}

// ========== ICMP 头部 ==========
#[repr(C)]
pub struct IcmpHeader {
    pub icmp_type: u8,
    pub code: u8,
    pub checksum: u16,
    pub identifier: u16,
    pub sequence_number: u16,
    pub data: [u8; 32],
}

impl IcmpHeader {
    pub fn new(seq: u16, id: u16) -> Self {
        Self {
            icmp_type: 8,  // Echo Request
            code: 0,
            checksum: 0,
            identifier: id,
            sequence_number: seq,
            data: [0; 32],
        }
    }

    pub fn calc_checksum(&mut self) {
        unsafe {
            self.checksum = 0;
            let slice = core::slice::from_raw_parts(
                self as *const _ as *const u8,
                core::mem::size_of::<IcmpHeader>(),
            );
            self.checksum = checksum(slice);
        }
    }
}

// ========== UDP 头部 ==========
#[repr(C)]
pub struct UdpHeader {
    pub src_port: u16,
    pub dst_port: u16,
    pub length: u16,
    pub checksum: u16,
}

// ========== ARP 缓存 ==========
pub struct ArpCache {
    entries: [(u32, [u8; 6]); 16],
    count: usize,
}

impl ArpCache {
    pub const fn new() -> Self {
        Self {
            entries: [([0; 6], 0usize); 16],
            count: 0,
        }
    }

    pub fn lookup(&self, ip: u32) -> Option<[u8; 6]> {
        for i in 0..self.count {
            if self.entries[i].0 == ip {
                return Some(self.entries[i].1);
            }
        }
        None
    }

    pub fn add(&mut self, ip: u32, mac: [u8; 6]) -> bool {
        // 先更新已有的
        for i in 0..self.count {
            if self.entries[i].0 == ip {
                self.entries[i].1 = mac;
                return true;
            }
        }
        // 添加新的
        if self.count < 16 {
            self.entries[self.count] = (ip, mac);
            self.count += 1;
            true
        } else {
            false
        }
    }
}

// ========== 通用校验和计算 ==========
pub fn checksum(data: &[u8]) -> u16 {
    let mut sum: u32 = 0;
    let mut i = 0;

    while i + 1 < data.len() {
        sum += (data[i] as u32) << 8 | (data[i + 1] as u32);
        i += 2;
    }

    if i < data.len() {
        sum += (data[i] as u32) << 8;
    }

    // 折叠进位
    while (sum >> 16) != 0 {
        sum = (sum & 0xFFFF) + (sum >> 16);
    }

    !(sum as u16)
}

// ========== 网络接口封装 ==========
pub struct NetworkInterface {
    pub rtl: Option<Rtl8139>,
    pub ip: u32,
    pub subnet_mask: u32,
    pub gateway: u32,
    pub arp: ArpCache,
}

impl NetworkInterface {
    pub fn new(rtl: Rtl8139, ip: u32, mask: u32, gw: u32) -> Self {
        Self {
            rtl: Some(rtl),
            ip,
            subnet_mask: mask,
            gateway: gw,
            arp: ArpCache::new(),
        }
    }

    pub fn send_icmp_ping(&mut self, target_ip: u32, seq: u16) -> bool {
        let mut rtl = match self.rtl.take() {
            Some(r) => r,
            None => return false,
        };

        rtl.init();

        // 构造 ICMP
        let mut icmp = IcmpHeader::new(seq, seq);
        icmp.calc_checksum();

        // 构造 IP
        let mut ip_hdr = IpHeader {
            version_ihl: 0x45,
            dscp_ecn: 0,
            total_length: (core::mem::size_of::<IpHeader>() + core::mem::size_of::<IcmpHeader>()) as u16,
            identification: 0,
            flags_fragment: 0,
            ttl: 64,
            protocol: IPPROTO_ICMP,
            checksum: 0,
            src_ip: self.ip,
            dst_ip: target_ip,
        };
        ip_hdr.calc_checksum();

        // 构建帧
        let mut frame = alloc::vec::Vec::new();
        // 目标 MAC（广播，ARP 未实现时暂时用）
        frame.extend_from_slice(&[0xFFu8; 6]);
        // 源 MAC
        let mac = rtl.mac_addr();
        frame.extend_from_slice(&mac);
        // EtherType: IPv4
        frame.extend_from_slice(&[0x08, 0x00]);
        // IP + ICMP
        unsafe {
            frame.extend_from_slice(core::slice::from_raw_parts(&ip_hdr as *const _ as *const u8, core::mem::size_of::<IpHeader>()));
            frame.extend_from_slice(core::slice::from_raw_parts(&icmp as *const _ as *const u8, core::mem::size_of::<IcmpHeader>()));
        }

        rtl.send(&frame);
        self.rtl = Some(rtl);
        true
    }
}

